ask.map:
function (doc) {
  if (doc.we_source && doc.we_source === "ask" && doc.we_timestamp) {
    emit(doc.we_timestamp, null);
  }
}

google.map:
function (doc) {
  var replies = 0, plusoners = 0, resharers = 0;
  if (doc.we_source && doc.we_source === "g+" && doc.id) {
    if (doc.object) {
      if (doc.object.replies) replies = doc.object.replies.totalItems;
      if (doc.object.plusoners) plusoners = doc.object.plusoners.totalItems;
      if (doc.object.resharers) resharers = doc.object.resharers.totalItems;
     }
    emit(doc.id, [doc._rev, doc.we_tags, replies, plusoners, resharers]);
  }
}

