edem630.map:
function(doc) {
  if (doc.we_tags && doc.we_tags.indexOf('edem630') > -1) {
    if (doc.we_link) {
      emit(doc.we_link, doc.id);
    } else {
      emit(doc.url, doc.id);
    }
  }
}
